/**
 * HUBE - Authentication Module
 * Sistema centralizado de autenticação para todas as features
 *
 * - Autentica uma vez por loja
 * - Salva token em cookie (com expiração de 24h)
 * - Fallback automático em caso de 401
 */

import { log, warn, error } from '../logger.js';
import mockAuthData from './mock.json';

// Variáveis de ambiente injetadas em build time
const AUTH_USE_MOCK = import.meta.env.AUTH_USE_MOCK;
const AUTH_API_URL = import.meta.env.AUTH_API_URL;

// Constantes
const DEFAULT_EXPIRES_IN = 86400; // 24 horas em segundos

/**
 * Gera o nome do cookie para o token da loja
 * @param {number} storeId - ID da loja
 * @returns {string} Nome do cookie
 */
function getCookieName(storeId) {
    return `hube-token-${storeId}`;
}

/**
 * Salva token em cookie
 * @param {number} storeId - ID da loja
 * @param {string} token - Token de autenticação
 * @param {number} expiresIn - Tempo de expiração em SEGUNDOS
 */
export function saveTokenToCookie(storeId, token, expiresIn = DEFAULT_EXPIRES_IN) {
    const cookieName = getCookieName(storeId);
    const expiresDate = new Date(Date.now() + expiresIn * 1000);

    const cookieParts = [
        `${cookieName}=${token}`,
        `expires=${expiresDate.toUTCString()}`,
        'Secure',
        'SameSite=Strict',
        'path=/'
    ];

    document.cookie = cookieParts.join('; ');

    log(`[HUBE Auth] 💾 Token salvo em cookie (expira em ${expiresIn}s = ${expiresIn / 86400} dias)`);
}

/**
 * Lê token do cookie
 * @param {number} storeId - ID da loja
 * @returns {string|null} Token ou null se não encontrado
 */
export function getTokenFromCookie(storeId) {
    const cookieName = getCookieName(storeId);
    const cookies = document.cookie.split('; ');

    for (const cookie of cookies) {
        const [name, value] = cookie.split('=');
        if (name === cookieName) {
            return value;
        }
    }

    return null;
}

/**
 * Remove token do cookie
 * @param {number} storeId - ID da loja
 */
export function clearTokenCookie(storeId) {
    const cookieName = getCookieName(storeId);

    // Define cookie com data passada para remover
    document.cookie = `${cookieName}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;

    log(`[HUBE Auth] 🗑️ Cookie de token removido para loja ${storeId}`);
}

/**
 * Autentica na API e retorna dados de autenticação
 * @param {number} storeId - ID da loja
 * @returns {Promise<Object>} { token, expiresIn }
 */
export async function authenticate(storeId) {
    // MODO MOCK: retorna dados mockados
    if (AUTH_USE_MOCK) {
        log('[HUBE Auth] 🔧 Modo MOCK ativado');

        // Simula delay de rede (200ms)
        await new Promise(resolve => setTimeout(resolve, 200));

        log(`[HUBE Auth] ✅ Autenticação mockada bem-sucedida`);
        return mockAuthData;
    }

    // MODO PRODUÇÃO: chama API real
    log(`[HUBE Auth] Autenticando loja ${storeId}...`);

    try {
        const response = await fetch(`${AUTH_API_URL}/${storeId}`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            }
        });

        if (!response.ok) {
            throw new Error(`Erro na autenticação: ${response.status}`);
        }

        const data = await response.json();

        // Valida resposta
        if (!data.token) {
            throw new Error('Token não encontrado na resposta da API');
        }

        log(`[HUBE Auth] ✅ Autenticação bem-sucedida para loja ${storeId}`);

        return {
            token: data.token,
            expiresIn: data.expiresIn || DEFAULT_EXPIRES_IN
        };

    } catch (err) {
        error(`[HUBE Auth] ❌ Erro ao autenticar loja ${storeId}:`, err);
        throw err;
    }
}

/**
 * Retorna o token do cookie ou autentica se necessário
 * @param {number} storeId - ID da loja
 * @returns {Promise<string>} Token de autenticação
 */
export async function getToken(storeId) {
    // Tenta recuperar token do cookie
    const cachedToken = getTokenFromCookie(storeId);

    if (cachedToken) {
        log(`[HUBE Auth] ✅ Token encontrado no cookie para loja ${storeId}`);
        return cachedToken;
    }

    // Token não existe ou expirou → autentica
    log(`[HUBE Auth] 🔑 Token não encontrado, autenticando...`);
    const authData = await authenticate(storeId);

    // Salva token no cookie
    saveTokenToCookie(storeId, authData.token, authData.expiresIn);

    return authData.token;
}

/**
 * Remove o token do cookie (força reautenticação)
 * @param {number} storeId - ID da loja
 */
export function clearToken(storeId) {
    clearTokenCookie(storeId);
}

/**
 * Verifica se existe token salvo para a loja
 * @param {number} storeId - ID da loja
 * @returns {boolean} True se existe token
 */
export function isAuthenticated(storeId) {
    return getTokenFromCookie(storeId) !== null;
}

/**
 * Faz uma requisição autenticada com fallback automático em caso de 401
 * @param {string} url - URL da requisição
 * @param {Object} options - Opções do fetch
 * @param {number} storeId - ID da loja
 * @returns {Promise<Response>} Resposta da requisição
 */
export async function makeAuthenticatedRequest(url, options = {}, storeId) {
    // Obtém token (do cookie ou autentica)
    let token = await getToken(storeId);

    // Adiciona token e storeId nos headers customizados
    const authOptions = {
        ...options,
        headers: {
            ...options.headers,
            'X-Api-Key': token,
            'X-Store-Id': storeId.toString()
        }
    };

    // Faz requisição
    let response = await fetch(url, authOptions);

    // Se 401 (Unauthorized) → token inválido/expirado
    if (response.status === 401) {
        warn(`[HUBE Auth] ⚠️ Token inválido (401), reautenticando...`);

        // Remove token antigo
        clearToken(storeId);

        // Autentica novamente
        token = await getToken(storeId);

        // Atualiza headers com novo token
        authOptions.headers['X-Api-Key'] = token;
        authOptions.headers['X-Store-Id'] = storeId.toString();

        // Retry da requisição
        response = await fetch(url, authOptions);

        if (response.status === 401) {
            throw new Error('Falha na autenticação após retry');
        }

        log(`[HUBE Auth] ✅ Requisição bem-sucedida após reautenticação`);
    }

    return response;
}

/**
 * Exporta funções principais do módulo de autenticação
 */
export default {
    authenticate,
    getToken,
    clearToken,
    isAuthenticated,
    makeAuthenticatedRequest,
    saveTokenToCookie,
    getTokenFromCookie,
    clearTokenCookie
};
