/**
 * HUBE - Script Loader
 * Carregamento dinâmico de features
 */

import { log, error } from '../../core/logger.js';

// Variável de ambiente injetada em build time
const CDN_BASE_URL = import.meta.env.CDN_BASE_URL || 'http://localhost:3000';

/**
 * Gera URL do script baseado no slug
 * @param {string} platform - Plataforma (nuvemshop, shopify, tray)
 * @param {string} slug - Slug do app (ex: "smartforms", "vcn")
 * @returns {string} URL completa do script
 */
export function getFeatureUrl(platform, slug) {
    return `${CDN_BASE_URL}/${platform}/${slug}.min.js`;
}

/**
 * Carrega um script dinamicamente
 * @param {string} url - URL do script
 * @returns {Promise} Resolve quando script carregar
 */
export function loadScript(url) {
    return new Promise((resolve, reject) => {
        // Verifica se já foi carregado
        if (document.querySelector(`script[src="${url}"]`)) {
            log(`[HUBE Loader] Script já carregado: ${url}`);
            resolve();
            return;
        }

        // Cria elemento script
        const script = document.createElement('script');
        script.src = url;
        script.type = 'text/javascript';
        script.async = true;

        // Eventos de sucesso/erro
        script.onload = () => {
            log(`[HUBE Loader] ✅ Script carregado: ${url}`);
            resolve();
        };

        script.onerror = () => {
            error(`[HUBE Loader] ❌ Erro ao carregar: ${url}`);
            reject(new Error(`Failed to load script: ${url}`));
        };

        // Adiciona no DOM
        document.head.appendChild(script);
    });
}

/**
 * Carrega script com retry automático
 * @param {string} url - URL do script
 * @param {number} retries - Tentativas (padrão: 3)
 * @returns {Promise}
 */
export async function loadScriptWithRetry(url, retries = 3) {
    for (let i = 0; i < retries; i++) {
        try {
            await loadScript(url);
            return; // sucesso
        } catch (err) {
            log(`[HUBE Loader] ⚠️ Tentativa ${i + 1}/${retries} falhou para ${url}`);

            if (i === retries - 1) {
                throw err; // última tentativa falhou
            }

            // Aguarda antes de retry (backoff exponencial: 1s, 2s, 4s)
            await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, i)));
        }
    }
}
