/**
 * HUBE - Apps API
 * Comunicação com API para buscar apps ativos
 */

import { log, error } from '../../core/logger.js';
import mockAppsData from './mock.json';

// Variáveis de ambiente injetadas em build time
const AUTH_USE_MOCK = import.meta.env.AUTH_USE_MOCK;
const APPS_API_URL = import.meta.env.APPS_API_URL;

/**
 * Busca apps ativos para a loja
 * @param {string} token - Token de autenticação
 * @param {number} storeId - ID da loja
 * @returns {Promise<Object>} { storeId, hasAllAccess, apps }
 */
export async function fetchApps(token, storeId) {
    // MODO MOCK: retorna dados mockados
    if (AUTH_USE_MOCK) {
        log('[HUBE Apps] 🔧 Modo MOCK ativado');

        // Simula delay de rede (200ms)
        await new Promise(resolve => setTimeout(resolve, 200));

        log('[HUBE Apps] ✅ Apps mockados carregados');
        return mockAppsData;
    }

    // MODO PRODUÇÃO: chama API real
    log(`[HUBE Apps] Buscando apps para loja ${storeId}...`);

    try {
        const response = await fetch(APPS_API_URL, {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json',
                'X-Api-Key': token,
                'X-Store-Id': storeId.toString()
            }
        });

        if (!response.ok) {
            throw new Error(`Erro ao buscar apps: ${response.status}`);
        }

        const data = await response.json();

        log(`[HUBE Apps] ✅ ${data.apps?.length || 0} apps encontrados`);

        return data;

    } catch (err) {
        error(`[HUBE Apps] ❌ Erro ao buscar apps:`, err);
        throw err;
    }
}
