/**
 * HUBE - Nuvemshop Bundle
 * Bundle principal que carrega features dinamicamente
 */

import { authenticate, saveTokenToCookie, getTokenFromCookie } from '../../core/auth/index.js';
import { fetchApps } from './api.js';
import { getFeatureUrl, loadScriptWithRetry } from './loader.js';
import { log, warn, error } from '../../core/logger.js';

/**
 * Identifica o storeId da loja Nuvemshop
 * @returns {number} ID da loja
 */
function getStoreId() {
    if (typeof window.LS === 'undefined') {
        throw new Error('API LS da Nuvemshop não encontrada');
    }
    return window.LS.store.id;
}

/**
 * Carrega e inicializa uma feature
 * @param {string} slug - Slug do app (ex: "smartforms")
 * @param {string} name - Nome curto do app
 * @param {number} storeId - ID da loja
 */
async function loadFeature(slug, name, storeId) {
    try {
        log(`[HUBE] 📦 Carregando ${name}...`);

        // Gera URL: http://localhost:3000/nuvemshop/{slug}.min.js
        const url = getFeatureUrl('nuvemshop', slug);

        // Carrega script (com retry)
        await loadScriptWithRetry(url);

        // Inicializa feature
        if (window.HubeFeatures?.[slug]?.init) {
            await window.HubeFeatures[slug].init();
            log(`[HUBE] ✅ ${name} inicializado`);
        } else {
            warn(`[HUBE] ⚠️ ${slug} carregado, mas sem método init()`);
        }

    } catch (err) {
        error(`[HUBE] ❌ Erro ao carregar ${name}:`, err);
        // Continua com próximos apps (não bloqueia)
    }
}

/**
 * Bootstrap principal
 */
(async function bootstrap() {
    try {
        log('[HUBE] 🚀 Iniciando bundle Nuvemshop...');

        // 1. Identifica loja
        const storeId = getStoreId();
        log(`[HUBE] 🏪 Store ID: ${storeId}`);

        // 2. Verifica se já tem token em cache
        let token = getTokenFromCookie(storeId);

        if (!token) {
            // Não tem token → autentica
            log('[HUBE] 🔑 Autenticando...');
            const authData = await authenticate(storeId);
            saveTokenToCookie(storeId, authData.token, authData.expiresIn);
            token = authData.token;
            log('[HUBE] ✅ Autenticado');
        } else {
            log('[HUBE] ✅ Token encontrado no cache');
        }

        // 3. Busca apps ativos
        log('[HUBE] 📋 Buscando apps ativos...');
        const appsData = await fetchApps(token, storeId);

        if (!appsData.apps || appsData.apps.length === 0) {
            log('[HUBE] ℹ️ Nenhum app ativo para esta loja');
            return;
        }

        log(`[HUBE] 📦 ${appsData.apps.length} app(s) ativo(s)`);

        // 4. Carrega cada app
        for (const app of appsData.apps) {
            await loadFeature(app.slug, app.short_name, storeId);
        }

        log('[HUBE] ✅ Bundle inicializado com sucesso');

    } catch (err) {
        error('[HUBE] ❌ Erro crítico no bundle:', err);
    }
})();
